import{_ as s,o as a,c as i,a2 as t}from"./chunks/framework.DfwzJIgY.js";const k=JSON.parse('{"title":"Constants & Enums","description":"","frontmatter":{},"headers":[],"relativePath":"reference/constants.md","filePath":"reference/constants.md"}'),n={name:"reference/constants.md"};function l(r,e,o,h,d,c){return a(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="constants-enums" tabindex="-1">Constants &amp; Enums <a class="header-anchor" href="#constants-enums" aria-label="Permalink to &quot;Constants &amp; Enums&quot;">​</a></h1><h2 id="the-no-magic-strings-rule" tabindex="-1">The no magic strings rule <a class="header-anchor" href="#the-no-magic-strings-rule" aria-label="Permalink to &quot;The no magic strings rule&quot;">​</a></h2><p>Any string used in more than one place lives in <code>helpers/constants.js</code>. Reference <code>LOCALE.EN</code>, not <code>&#39;en&#39;</code>. Reference <code>STATUS.ACTIVE</code>, not <code>&#39;active&#39;</code>. If a string literal appears — or is likely to appear — in more than one file, it belongs in constants.</p><h2 id="helpers-constants-js-structure" tabindex="-1">helpers/constants.js structure <a class="header-anchor" href="#helpers-constants-js-structure" aria-label="Permalink to &quot;helpers/constants.js structure&quot;">​</a></h2><div class="language-js vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> LOCALE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { EN: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;en&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, ES: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;es&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, FR: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;fr&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> STATUS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { ACTIVE: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;active&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, INACTIVE: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;inactive&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, PENDING: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;pending&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Each constant is a plain object whose keys are UPPER_CASE shorthand and whose values are the canonical string (or number) the rest of the codebase uses.</p><h2 id="the-dual-export-pattern" tabindex="-1">The dual export pattern <a class="header-anchor" href="#the-dual-export-pattern" aria-label="Permalink to &quot;The dual export pattern&quot;">​</a></h2><div class="language-js vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">module</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">exports</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { LOCALE, LOCALE_ARR: Object.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">values</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">LOCALE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), STATUS, STATUS_ARR: Object.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">values</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">STATUS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Why: some places need the object (for dot-access in code), some need the array (for Joi <code>.valid()</code> validation). Exporting both from the same source keeps them in sync automatically.</p><h2 id="naming-rules" tabindex="-1">Naming rules <a class="header-anchor" href="#naming-rules" aria-label="Permalink to &quot;Naming rules&quot;">​</a></h2><ul><li>The object name is <code>UPPER_CASE</code> (<code>LOCALE</code>, <code>STATUS</code>, <code>TOKEN_TYPE</code>).</li><li>Values can be lowercase strings (<code>LOCALE.EN = &#39;en&#39;</code>) — that is fine and intentional.</li><li>The array variant appends <code>_ARR</code> (<code>LOCALE_ARR</code>) or uses a plural name — be consistent within the file.</li></ul><h2 id="adding-a-new-constant" tabindex="-1">Adding a new constant <a class="header-anchor" href="#adding-a-new-constant" aria-label="Permalink to &quot;Adding a new constant&quot;">​</a></h2><p>Use the <code>add-constant</code> skill. Never add raw strings anywhere else. The skill ensures the constant and its <code>_ARR</code> twin are both exported and that all call sites are updated to reference the constant.</p><h2 id="migrations-stay-literal" tabindex="-1">Migrations stay literal <a class="header-anchor" href="#migrations-stay-literal" aria-label="Permalink to &quot;Migrations stay literal&quot;">​</a></h2><p>Migrations are frozen snapshots of schema state at a point in time. They use literal strings, not constants. That is intentional and correct — migrations are never refactored, so the duplication is acceptable and expected.</p><h2 id="examples-of-what-lives-here" tabindex="-1">Examples of what lives here <a class="header-anchor" href="#examples-of-what-lives-here" aria-label="Permalink to &quot;Examples of what lives here&quot;">​</a></h2><ul><li><code>LOCALE</code> — language codes (<code>en</code>, <code>es</code>, <code>fr</code>)</li><li><code>STATUS</code> — entity statuses (<code>active</code>, <code>inactive</code>, <code>pending</code>)</li><li><code>ROLE</code> — user roles (<code>admin</code>, <code>member</code>, etc.)</li><li><code>TOKEN_TYPE</code> — token kinds (<code>access</code>, <code>refresh</code>)</li><li>Any other enum-like set used in two or more places</li></ul>`,17)])])}const E=s(n,[["render",l]]);export{k as __pageData,E as default};
